    56→function useCardBorderImage(race: Race | null): string {
    57→  const [borderImageUrl, setBorderImageUrl] = useState("");
    58→
    59→  useEffect(() => {
    60→    let cancelled = false;
    61→    const path = getCardBorderPath(race);
    62→    void loadBlpDataUrl(path)
    63→      .then((url) => loadDataUrlImage(url))
    64→      .then((img) => {
    65→        if (cancelled) return;
    66→        setBorderImageUrl(composeBorderImageFromAtlas(img));
    67→      })
    68→      .catch((err) => console.error(err));
    69→    return () => {
    70→      cancelled = true;
    71→    };
    72→  }, [race]);
    73→
    74→  return borderImageUrl;
    75→}
    76→
    77→
    78→function useSupplyIcon(): string {
    79→  const [url, setUrl] = useState("");
    80→  useEffect(() => {
    81→    void loadBlpDataUrl("./resources/ResourceSupply.blp").then(setUrl);
    82→  }, []);
    83→  return url;
    84→}
    85→
    86→function playSound(name: string) {
    87→  const audio = new Audio(`./sound/${name}.wav`);
    88→  audio.play().catch(() => {
    89→    if (name !== "key_moment") {
    90→      new Audio("./sound/key_moment.wav").play().catch(() => {});
    91→    }
    92→  });
    93→}
