    95→function KeyMomentToast({
    96→  step,
    97→  onDismiss,
    98→}: {
    99→  step: BuildStep;
   100→  onDismiss: () => void;
   101→}) {
   102→  useEffect(() => {
   103→    const t = setTimeout(onDismiss, 4500);
   104→    return () => clearTimeout(t);
   105→  }, [onDismiss]);
   106→
   107→  return (
   108→    <div className="key-moment-toast" onClick={onDismiss}>
   109→      <span className="key-moment-label">⚡ Key Moment</span>
   110→      <span className="key-moment-text">{step.instruction}</span>
   111→      <span className="key-moment-time">{step.time}</span>
   112→    </div>
   113→  );
   114→}
