   116→const DIFFICULTY_CLASS: Record<string, string> = {
   117→  Beginner: "build-card-difficulty--beginner",
   118→  Intermediate: "build-card-difficulty--intermediate",
   119→  Advanced: "build-card-difficulty--advanced",
   120→};
   121→
   122→const HERO_ICONS: Record<string, string> = {
   123→  Archmage: "BTNHeroArchMage",
   124→  Blademaster: "BTNHeroBlademaster",
   125→  "Blood Mage": "BTNHeroBloodElfPrince",
   126→  "Crypt Lord": "BTNHeroCryptLord",
   127→  "Death Knight": "BTNHeroDeathKnight",
   128→  "Demon Hunter": "BTNHeroDemonHunter",
   129→  "Far Seer": "BTNHeroFarseer",
   130→  "Keeper of the Grove": "BTNKeeperOfTheGrove",
   131→  Lich: "BTNHeroLich",
   132→  "Mountain King": "BTNHeroMountainKing",
   133→  Paladin: "BTNHeroPaladin",
   134→  "Priestess of the Moon": "BTNPriestessOfTheMoon",
   135→  "Shadow Hunter": "BTNShadowHunter",
   136→  "Tauren Chieftain": "BTNHeroTaurenChieftain",
   137→  Warden: "BTNHeroWarden",
   138→};
   139→
   140→function HeroIcon({ heroName }: { heroName: string }) {
   141→  const [iconUrl, setIconUrl] = useState("");
   142→  useEffect(() => {
   143→    let cancelled = false;
   144→    const file = HERO_ICONS[heroName];
   145→    if (!file) return;
   146→    void loadBlpDataUrl(`./buttons/command/${file}.blp`).then((url) => {
   147→      if (!cancelled) setIconUrl(url);
   148→    });
   149→    return () => {
