   164→interface BuildCardProps {
   165→  build: BuildOrder;
   166→  elapsed: number;
   167→  running: boolean;
   168→  borderImageUrl: string;
   169→}
   170→
   171→function BuildCard({
   172→  build,
   173→  elapsed,
   174→  running,
   175→  borderImageUrl,
   176→}: BuildCardProps) {
   177→  const tableRef = useRef<HTMLDivElement>(null);
   178→  const [scrollPct, setScrollPct] = useState(0);
   179→  const [containerHalf, setContainerHalf] = useState(0);
   180→  const [centerScroll, setCenterScroll] = useState(true);
   181→  const [keyToast, setKeyToast] = useState<BuildStep | null>(null);
   182→  const [toastKey, setToastKey] = useState(0);
   183→  const scrollingFromBar = useRef(false);
   184→  const prevActiveRef = useRef(-1);
   185→  const supplyIconUrl = useSupplyIcon();
   186→
   187→  const activeStepIndex = (() => {
   188→    let idx = -1;
   189→    for (let i = 0; i < build.steps.length; i++) {
   190→      if (parseStepTime(build.steps[i].time) <= elapsed) idx = i;
   191→    }
   192→    return idx;
   193→  })();
   194→
   195→  // Measure container height for centering spacers
   196→  useEffect(() => {
   197→    const el = tableRef.current;
   198→    if (!el) return;
   199→    const ro = new ResizeObserver(() => setContainerHalf(el.clientHeight / 2));
   200→    ro.observe(el);
   201→    return () => ro.disconnect();
   202→  }, []);
   203→
   204→  // Sync native scroll → scrollbar percentage
   205→  useEffect(() => {
   206→    const el = tableRef.current;
   207→    if (!el) return;
   208→    const handler = () => {
   209→      if (scrollingFromBar.current) return;
   210→      const maxScroll = el.scrollHeight - el.clientHeight;
   211→      if (maxScroll <= 0) {
   212→        setScrollPct(0);
   213→        return;
   214→      }
   215→      setScrollPct((el.scrollTop / maxScroll) * 100);
   216→    };
   217→    el.addEventListener("scroll", handler, { passive: true });
   218→    return () => el.removeEventListener("scroll", handler);
   219→  }, []);
   220→
   221→  // Scrollbar → native scroll
   222→  const handleScrollbarChange = useCallback((pct: number) => {
   223→    setScrollPct(pct);
   224→    const el = tableRef.current;
   225→    if (!el) return;
   226→    const maxScroll = el.scrollHeight - el.clientHeight;
   227→    if (maxScroll <= 0) return;
   228→    scrollingFromBar.current = true;
   229→    el.scrollTop = (pct / 100) * maxScroll;
   230→    requestAnimationFrame(() => {
   231→      scrollingFromBar.current = false;
   232→    });
   233→  }, []);
   234→
   235→  // Clear toast on reset
   236→  useEffect(() => {
   237→    if (elapsed === 0) {
   238→      setKeyToast(null);
   239→      prevActiveRef.current = -1;
   240→    }
   241→  }, [elapsed]);
   242→
   243→  // Key moment trigger
   244→  useEffect(() => {
   245→    const prev = prevActiveRef.current;
   246→    prevActiveRef.current = activeStepIndex;
   247→    if (activeStepIndex > prev && activeStepIndex >= 0) {
   248→      const step = build.steps[activeStepIndex];
   249→      if (step?.isKey) {
   250→        setKeyToast(step);
   251→        setToastKey((k) => k + 1);
   252→        playSound(step.sound ?? "key_moment");
   253→      }
   254→    }
   255→  }, [activeStepIndex, build.steps]);
   256→
   257→  // Auto-scroll active step
   258→  useEffect(() => {
   259→    if (activeStepIndex < 0 || !tableRef.current) return;
   260→    const el = tableRef.current;
   261→    const row = el.querySelectorAll(".build-step-row")[activeStepIndex] as
   262→      | HTMLElement
   263→      | undefined;
   264→    if (!row) return;
   265→    if (centerScroll) {
   266→      const targetScrollTop =
   267→        row.offsetTop - el.clientHeight / 2 + row.offsetHeight / 2;
   268→      el.scrollTo({ top: targetScrollTop, behavior: "smooth" });
   269→    } else {
   270→      row.scrollIntoView({ block: "nearest", behavior: "smooth" });
   271→    }
   272→  }, [activeStepIndex, centerScroll]);
   273→
   274→  // border-image applied only to the active row; all rows already reserve
   275→  // 6px transparent border space in CSS so nothing shifts.
   276→  const activeBorderStyle: React.CSSProperties | undefined = borderImageUrl
   277→    ? {
   278→        borderImageSource: `url("${borderImageUrl}")`,
   279→        borderImageSlice: 64,
   280→        borderImageWidth: 1,
   281→        borderImageRepeat: "round",
   282→      }
   283→    : undefined;
   284→
   285→  return (
   286→    <div className="build-card">
   287→      {/* ── Full-width header banner ── */}
   288→      <div className="build-card-header">
   289→        {build.heroes?.[0] && (
   290→          <div className="build-card-hero-col">
   291→            <HeroIcon heroName={build.heroes[0]} />
   292→            <span className="build-card-hero-name">{build.heroes[0]}</span>
   293→          </div>
   294→        )}
   295→        <div className="build-card-header-main">
   296→          <h4 className="build-card-title">{build.name}</h4>
   297→          <div className="build-card-badges">
   298→            {build.vs && (
   299→              <span className="build-card-matchup">vs {build.vs}</span>
   300→            )}
   301→            {build.difficulty && (
   302→              <span
   303→                className={`build-card-difficulty ${DIFFICULTY_CLASS[build.difficulty] ?? ""}`}
   304→              >
   305→                {build.difficulty}
   306→              </span>
   307→            )}
   308→          </div>
   309→        </div>
   310→
   311→        {/* Timer — right-most element in header */}
   312→        <div className="build-card-timer">
   313→          <span className="build-card-elapsed">{formatTime(elapsed)}</span>
   314→          <div className="build-card-controls">
   315→            <GlueSmallButton onClick={running ? pauseTimer : startTimer}>
   316→              {running ? "Pause" : "Start"}
   317→            </GlueSmallButton>
   318→            <GlueSmallButton
   319→              onClick={resetTimer}
   320→              disabled={elapsed === 0 && !running}
   321→            >
   322→              Reset
   323→            </GlueSmallButton>
   324→          </div>
   325→          <BuildCheckbox
   326→            checked={centerScroll}
   327→            onChange={setCenterScroll}
   328→            label="Center Scroll"
   329→          />
   330→        </div>
   331→      </div>
   332→
   333→      {/* Key moment slot — always present to reserve space */}
   334→      <div className="key-moment-slot">
   335→        {keyToast && (
   336→          <KeyMomentToast
   337→            key={toastKey}
   338→            step={keyToast}
   339→            onDismiss={() => setKeyToast(null)}
   340→          />
   341→        )}
   342→      </div>
   343→
   344→      {/* Steps — full width */}
   345→      <div className="build-card-steps-wrapper">
   346→        <div className="build-card-steps" ref={tableRef}>
   347→          <table className="build-steps-table">
   348→            <thead>
   349→              <tr>
   350→                <th>#</th>
   351→                <th>Time</th>
   352→                <th>Instruction</th>
   353→                <th>
   354→                  {supplyIconUrl && (
   355→                    <img
   356→                      src={supplyIconUrl}
   357→                      alt=""
   358→                      className="build-step-food-icon"
   359→                    />
   360→                  )}
   361→                  Food
   362→                </th>
   363→              </tr>
   364→            </thead>
   365→            <tbody>
   366→              {centerScroll && (
   367→                <tr aria-hidden="true" style={{ height: containerHalf }}>
   368→                  <td colSpan={4} />
   369→                </tr>
   370→              )}
   371→              {build.steps.map((step, j) => {
   372→                const isActive = j === activeStepIndex;
   373→                const isPast = j < activeStepIndex;
   374→                return (
   375→                  <tr
   376→                    key={j}
   377→                    className={`build-step-row${isPast ? " build-step-row--past" : ""}${isActive ? " build-step-row--active" : ""}`}
   378→                    style={isActive ? activeBorderStyle : undefined}
   379→                  >
   380→                    <td className="build-step-order">{step.order}</td>
   381→                    <td className="build-step-time">{step.time}</td>
   382→                    <td className="build-step-instruction">
   383→                      {step.instruction}
   384→                    </td>
   385→                    <td className="build-step-food">
   386→                      {supplyIconUrl && (
   387→                        <img
   388→                          src={supplyIconUrl}
   389→                          alt=""
   390→                          className="build-step-food-icon"
   391→                        />
   392→                      )}
   393→                      {step.food}
   394→                    </td>
   395→                  </tr>
   396→                );
   397→              })}
   398→              {centerScroll && (
   399→                <tr aria-hidden="true" style={{ height: containerHalf }}>
   400→                  <td colSpan={4} />
   401→                </tr>
   402→              )}
   403→            </tbody>
   404→          </table>
   405→        </div>
   406→        <GlueScrollbar value={scrollPct} onChange={handleScrollbarChange} />
   407→      </div>
   408→    </div>
   409→  );
   410→}
   411→
   412→export default function BuildOrdersSection() {
   413→  const running = useTimerRunning();
   414→  const elapsed = useElapsedSeconds();
   415→  const currentRace = useCurrentRace();
   416→  const borderImageUrl = useCardBorderImage(currentRace);
   417→  const allBuilds = useBuildOrders();
   418→
   419→  const relevantBuilds = allBuilds.filter(
   420→    (b) => !currentRace || b.race === currentRace,
   421→  );
   422→
   423→  const [selectedIndex, setSelectedIndex] = useState(0);
   424→  const [importStatus, setImportStatus] = useState("");
   425→  const fileInputRef = useRef<HTMLInputElement>(null);
   426→
   427→  // Reset selection and timer when race changes
   428→  useEffect(() => {
   429→    setSelectedIndex(0);
   430→    resetTimer();
   431→  }, [currentRace]);
   432→
   433→  const selectedBuild =
   434→    relevantBuilds.length > 0
   435→      ? relevantBuilds[Math.min(selectedIndex, relevantBuilds.length - 1)]
   436→      : null;
   437→
   438→  // Build dropdown option keys — use indices as stable identifiers
   439→  const optionKeys = relevantBuilds.map((_, i) => String(i));
   440→
   441→  const handleImport = useCallback(() => {
   442→    fileInputRef.current?.click();
   443→  }, []);
   444→
   445→  const handleExport = useCallback(() => {
   446→    if (!selectedBuild) return;
   447→    // Build a clean object with properties ordered to match the BuildOrder interface
   448→    const clean: Record<string, unknown> = {
   449→      name: selectedBuild.name,
   450→      race: selectedBuild.race,
   451→    };
   452→    if (selectedBuild.vs) clean.vs = selectedBuild.vs;
   453→    clean.description = selectedBuild.description;
   454→    if (selectedBuild.difficulty) clean.difficulty = selectedBuild.difficulty;
   455→    clean.steps = selectedBuild.steps;
   456→    if (selectedBuild.note) clean.note = selectedBuild.note;
   457→    if (selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0) {
   458→      clean.skillOrder = selectedBuild.skillOrder;
   459→    }
   460→    const json = JSON.stringify([clean], null, 2);
   461→    const blob = new Blob([json], { type: "application/json" });
   462→    const url = URL.createObjectURL(blob);
   463→    const a = document.createElement("a");
   464→    a.href = url;
   465→    a.download = `${selectedBuild.name.replace(/[^a-zA-Z0-9_-]/g, "_")}.json`;
   466→    a.click();
   467→
   468→    URL.revokeObjectURL(url);
   469→  }, [selectedBuild]);
   470→
   471→  const handleFileChange = useCallback(
   472→    (e: React.ChangeEvent<HTMLInputElement>) => {
   473→      const file = e.target.files?.[0];
   474→      if (!file) return;
   475→
   476→      const reader = new FileReader();
   477→      reader.onload = () => {
   478→        try {
   479→          const json = JSON.parse(reader.result as string);
   480→          const count = importBuilds(json);
   481→          if (count > 0) {
   482→            setImportStatus(`Imported ${count} build${count > 1 ? "s" : ""}`);
   483→          } else {
   484→            setImportStatus("No valid builds found in file");
   485→          }
   486→        } catch {
   487→          setImportStatus("Invalid JSON file");
   488→        }
   489→        // Clear so the same file can be re-imported
   490→        e.target.value = "";
   491→        setTimeout(() => setImportStatus(""), 4000);
   492→      };
   493→      reader.readAsText(file);
   494→    },
   495→    [],
   496→  );
   497→
   498→  return (
   499→    <div className="tab-content">
   500→      <section className="section-card build-orders-section">
   501→        <div className="build-orders-toolbar">
   502→          <h3>Build Orders</h3>
   503→          <div className="build-orders-toolbar-actions">
   504→            <div className="build-orders-race-picker">
   505→              <GlueDropdown
   506→                options={RACES}
   507→                value={currentRace}
   508→                onChange={(v) => setCurrentRace(v as Race)}
   509→                label={(v) => RACE_LABELS[v as Race] ?? v}
   510→              />
   511→            </div>
   512→            {relevantBuilds.length > 1 && (
   513→              <GlueDropdown
   514→                options={optionKeys}
   515→                value={String(
   516→                  Math.min(selectedIndex, relevantBuilds.length - 1),
   517→                )}
   518→                onChange={(v) => {
   519→                  setSelectedIndex(Number(v));
   520→                  resetTimer();
   521→                }}
   522→                label={(v) => relevantBuilds[Number(v)]?.name ?? ""}
   523→              />
   524→            )}
   525→            <GlueBorderedButton onClick={handleImport}>
   526→              Import
   527→            </GlueBorderedButton>
   528→            <GlueBorderedButton
   529→              onClick={handleExport}
   530→              disabled={!selectedBuild}
   531→            >
   532→              Export
   533→            </GlueBorderedButton>
   534→            <input
   535→              ref={fileInputRef}
   536→              type="file"
   537→              accept=".json"
   538→              className="build-import-input"
   539→              onChange={handleFileChange}
   540→            />
   541→          </div>
   542→        </div>
   543→        {importStatus && (
   544→          <div className="build-import-status">{importStatus}</div>
   545→        )}
   546→
   547→        {!selectedBuild ? (
   548→          <p className="build-card-empty">
   549→            No build orders available for this race.
   550→          </p>
   551→        ) : (
   552→          <>
   553→            <BuildCard
   554→              key={`${currentRace}-${selectedIndex}`}
   555→              build={selectedBuild}
   556→              elapsed={elapsed}
   557→              running={running}
   558→              borderImageUrl={borderImageUrl}
   559→            />
   560→            {selectedBuild.skillOrder &&
   561→              selectedBuild.skillOrder.length > 0 && (
   562→                <SkillOrderSection skillOrder={selectedBuild.skillOrder} />
   563→              )}
   564→            <BuildOrderInputSection />
   565→          </>
   566→        )}
   567→      </section>
   568→      <FooterSection race={currentRace} />
   569→    </div>
   570→  );
   571→}
