.wc3-bar {
  position: relative;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
}

.wc3-bar + .wc3-bar {
  margin-top: 8px;
}

.wc3-bar--large {
  height: 20px;
}

.wc3-bar--unit {
  width: min(
    100%,
    182.93px
  ); /* HPBarConsoleSmall/ManaBarConsoleSmall frame ratio: 0.04065 / 0.004 */
  height: 18px;
}

.wc3-bar--compact {
  width: min(
    100%,
    157.14px
  ); /* XpBarConsole/TimerBar frame ratio: 0.17776 / 0.01810 */
  height: 16px;
}

.wc3-bar--build {
  width: min(
    100%,
    163.7px
  ); /* BuildProgressBar frame ratio: 0.10538 / 0.01030 */
}

.wc3-bar-track,
.wc3-bar-border {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill-wrap {
  position: absolute;
  inset: 0 auto 0 0;
  overflow: hidden;
  transition: width 620ms ease;
}

.wc3-bar-fill,
.wc3-bar-highlight {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill--health {
  filter: saturate(1.18);
}

.wc3-bar-fill--mana {
  filter: saturate(1.2) hue-rotate(6deg);
}

.wc3-bar-fill--progress {
  filter: saturate(1.05);
}

.wc3-bar-fill--build {
  filter: saturate(1.12) hue-rotate(-9deg);
}

.wc3-bar-highlight {
  mix-blend-mode: screen;
  opacity: 0.62;
}

.wc3-bar-segments {
  position: absolute;
  inset: 2px;
  pointer-events: none;
  background-image: repeating-linear-gradient(
    to right,
    rgba(0, 0, 0, 0.38) 0 1px,
    rgba(0, 0, 0, 0) 1px 10%
  );
  opacity: 0.55;
}

.wc3-bar-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #f6f8ff;
  font-size: 0.74rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.wc3-bar--compact .wc3-bar-text {
  font-size: 0.68rem;
}

.loading-preview {
  display: flex;
  justify-content: center;
}

.loading-bar-composite {
  position: relative;
  width: min(100%, 640px);
  aspect-ratio: 8.007 / 1; /* LoadBar.mdx border geoset ratio: 0.45804 / 0.05720 */
  height: auto;
  max-height: 80px;
  overflow: visible;
}

.loading-bar-composite .lb-track {
  position: absolute;
  overflow: hidden;
}

.loading-bar-composite .lb-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
}

.loading-bar-composite .lb-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 0%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
  transition: width 90ms linear;
  will-change: width;
}

.loading-bar-composite .lb-border,
.loading-bar-composite .lb-glass {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  object-fit: fill;
  pointer-events: none;
}

.loading-bar-composite .lb-border {
  z-index: 1;
}

.loading-bar-composite .lb-glass {
  z-index: 2;
  opacity: 1;
}

.loading-bar-composite .lb-glow {
  position: absolute;
  display: block;
  object-fit: fill;
  z-index: 4;
  mix-blend-mode: screen;
  mix-blend-mode: plus-lighter;
  pointer-events: none;
  transition:
    width 90ms linear,
    opacity 90ms linear;
}

.loading-bar-composite .lb-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5;
  color: #f6f8ff;
